#include <bits/stdc++.h>
using namespace std;
int main(){
    long long n;
    cin>>n;
    long long a[1000010]{0};
    for(int i=0;i<n;i++){
        cin>>a[i];
    }
    sort(a,a+n);
    long long b=0,t=0;
    for(int i=0;i<n;i++){
		while(a[t]<i+1&&t<n){
			t++;
		}
		if(a[t]>=i+1){
			b++;
			t++;
		}
		else{
			break;
		}
	}
	cout<<b;
	return 0;
}
